#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 1e5+5;
int n,Q,a[N],t[N*4];
vector<int> g[N];
int Fa[N],dep[N],sz[N],wc[N];
int top[N],dfn[N],Cnt,fd[N];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void DFS1(int u,int fa){
    Fa[u]=fa,sz[u]=1;
    dep[u]=dep[fa]+1;
    for(int v:g[u])if(v^fa){
        DFS1(v,u),sz[u]+=sz[v];
        if(sz[v]>sz[wc[u]])wc[u]=v;
    }return;
}
void DFS2(int u,int Top){
    top[u]=Top;
    dfn[u]=(++Cnt),fd[Cnt]=u;
    if(wc[u])DFS2(wc[u],Top);
    for(int v:g[u])
        if(v^Fa[u]&&v^wc[u])DFS2(v,v);return;
}
int ls(int u){return (u<<1);}
int rs(int u){return (u<<1|1);}
void push_up(int u){
    t[u]=t[ls(u)]^t[rs(u)];return;
}
void build(int u,int l,int r){
    if(l==r){t[u]=a[fd[l]];return;}
    int mid=(l+r)/2;
    build(ls(u),l,mid);build(rs(u),mid+1,r);
    push_up(u);return;
}
void change(int u,int l,int r,int LR,int k){
    if(l>LR||r<LR)return;
    if(l==r){t[u]=k;return;}
    int mid=(l+r)/2;
    change(ls(u),l,mid,LR,k);
    change(rs(u),mid+1,r,LR,k);
    push_up(u);return;
}
int ask(int u,int l,int r,int L,int R){
    if(r<L||R<l)return 0;
    if(L<=l&&r<=R)return t[u];
    int mid=(l+r)/2,res=0;
    res^=ask(ls(u),l,mid,L,R);
    res^=ask(rs(u),mid+1,r,L,R);
    return res;
}
int query(int x,int y){
    int res=0;
    while(top[x]!=top[y]){
        if(dfn[top[x]]<dfn[top[y]])swap(x,y);
        res^=ask(1,1,n,dfn[top[x]],dfn[x]);
        x=Fa[top[x]];
    }if(dfn[x]>dfn[y])swap(x,y);
    res^=ask(1,1,n,dfn[x],dfn[y]);
    return res;
}
int main(){
    n=read(),Q=read();
    for(int i=1;i<=n;i++)a[i]=read();
    for(int i=1;i<n;i++){
        int x=read(),y=read();
        g[x].pb(y),g[y].pb(x);
    }DFS1(1,0);DFS2(1,0);
    build(1,1,n);
    while(Q--){
        int opt=read(),x=read(),y=read();
        if(opt==1)change(1,1,n,dfn[x],y);
        else cout<<query(x,y)<<"\n";
    }
    return 0;
}
